    public static boolean isTimestampValid(String messageId, Date created, Date expires) {
        if (created == null) {
            return false;
        }

        Date now = new Date();

        if (created.after(now)) {
            return false;
        }

        if (expires != null && expires.before(now)) {
            return false;
        }

        long age = now.getTime() - created.getTime();
        if (age > TIMESTAMP_VALIDITY_MS) {
            return false;
        }

        if (messageId != null && !messageId.isEmpty()) {
            if (processedTimestamps.contains(messageId)) {
                return false;
            }
            processedTimestamps.add(messageId);
        }

        return true;
    }

