class SecurityHandler implements SOAPHandler<SOAPMessageContext> {

    private static final String WSU_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd";
    private static final String WSSE_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd";

    @Override
    public boolean handleMessage(SOAPMessageContext context) {
        Boolean outbound = (Boolean) context.get(MessageContext.MESSAGE_OUTBOUND_PROPERTY);

        if (!outbound) {
            try {
                SOAPMessage message = context.getMessage();
                SOAPHeader header = message.getSOAPHeader();

                if (header == null) {
                    throw new SecurityException("Missing SOAP header");
                }

                TimestampInfo timestampInfo = extractTimestamp(header);

                if (timestampInfo == null) {
                    throw new SecurityException("Missing WS-Security timestamp");
                }

                if (!PaymentService.isTimestampValid(timestampInfo.messageId, timestampInfo.created, timestampInfo.expires)) {
                    throw new SecurityException("Invalid or expired timestamp");
                }

            } catch (SecurityException e) {
                throw e;
            } catch (Exception e) {
                throw new SecurityException("Error validating security: " + e.getMessage(), e);
            }
        }

        return true;
    }

    private TimestampInfo extractTimestamp(SOAPHeader header) throws Exception {
        TimestampInfo info = new TimestampInfo();

        Iterator<?> securityHeaders = header.getChildElements(new QName(WSSE_NS, "Security"));

        if (!securityHeaders.hasNext()) {
            return null;
        }

        SOAPElement securityElement = (SOAPElement) securityHeaders.next();

        Iterator<?> timestampElements = securityElement.getChildElements(new QName(WSU_NS, "Timestamp"));

        if (!timestampElements.hasNext()) {
            return null;
        }

        SOAPElement timestampElement = (SOAPElement) timestampElements.next();

        String messageId = timestampElement.getAttributeValue(new QName(WSU_NS, "Id"));
        info.messageId = messageId;

        Iterator<?> createdElements = timestampElement.getChildElements(new QName(WSU_NS, "Created"));
        if (createdElements.hasNext()) {
            SOAPElement createdElement = (SOAPElement) createdElements.next();
            String createdValue = createdElement.getTextContent();
            info.created = parseTimestamp(createdValue);
        }

        Iterator<?> expiresElements = timestampElement.getChildElements(new QName(WSU_NS, "Expires"));
        if (expiresElements.hasNext()) {
            SOAPElement expiresElement = (SOAPElement) expiresElements.next();
            String expiresValue = expiresElement.getTextContent();
            info.expires = parseTimestamp(expiresValue);
        }

        return info;
    }

    private Date parseTimestamp(String timestamp) {
        try {
            SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'");
            sdf.setTimeZone(TimeZone.getTimeZone("UTC"));
            return sdf.parse(timestamp);
        } catch (Exception e) {
            try {
                SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss'Z'");
                sdf.setTimeZone(TimeZone.getTimeZone("UTC"));
                return sdf.parse(timestamp);
            } catch (Exception ex) {
                return null;
            }
        }
    }

    @Override
    public boolean handleFault(SOAPMessageContext context) {
        return true;
    }

    @Override
    public void close(MessageContext context) {
    }

    @Override
    public Set<QName> getHeaders() {
        return new HashSet<>(Arrays.asList(new QName(WSSE_NS, "Security")));
    }

    static class TimestampInfo {
        String messageId;
        Date created;
        Date expires;
    }
}

